def solve(words: list[str]) -> list[int]:
    n = len(words)
    answer = [0] * n

    # Build a trie to store the words
    class TrieNode:
        def __init__(self):
            self.children = {}

    root = TrieNode()

    # Build the trie
    for i, word in enumerate(words):
        node = root
        for c in word:
            if c not in node.children:
                node.children[c] = TrieNode()
            node = node.children[c]

    # Function to find the longest common prefix between two words
    def lcp(word1, word2):
        min_len = min(len(word1), len(word2))
        for i in range(min_len):
            if word1[i] != word2[i]:
                return i
        return min_len

    # For each index, remove it and compute the answer
    for i in range(n):
        # Remove the ith word
        # We need to find the longest common prefix between adjacent words
        max_lcp = 0
        for j in range(n):
            if j == i:
                continue
            if j > 0:
                current_lcp = lcp(words[j-1], words[j])
                if current_lcp > max_lcp:
                    max_lcp = current_lcp
        answer[i] = max_lcp

    return answer
